# lib/admin_dashboard/queries/user_queries.ex
defmodule AdminDashboard.Queries.UserQueries do
  @moduledoc """
  Secure raw SQL queries for the admin dashboard.
  Always uses parameterized queries to prevent SQL injection.
  """

  alias AdminDashboard.Repo

  @doc """
  Fetches users by role using a parameterized query.
  NEVER use string interpolation for user input in SQL queries.

  ## DANGEROUS (DO NOT DO THIS):
      query(Repo, "SELECT * FROM users WHERE role='#{role}'")

  ## SAFE (parameterized):
      query(Repo, "SELECT * FROM users WHERE role = $1", [role])
  """
  def get_users_by_role(role) when is_binary(role) do
    # Parameterized query - $1 is a placeholder, value is passed separately
    Ecto.Adapters.SQL.query(
      Repo,
      "SELECT * FROM users WHERE role = $1",
      [role]
    )
  end

  @doc """
  Fetches users with multiple dynamic filters, all parameterized.
  """
  def filter_users(filters) when is_map(filters) do
    {where_clauses, params} = build_where_clauses(filters)

    query =
      if where_clauses == [] do
        "SELECT id, username, email, role, inserted_at FROM users"
      else
        "SELECT id, username, email, role, inserted_at FROM users WHERE " <>
          Enum.join(where_clauses, " AND ")
      end

    case Ecto.Adapters.SQL.query(Repo, query, params) do
      {:ok, %{rows: rows, columns: columns}} ->
        {:ok, Enum.map(rows, fn row -> Enum.zip(columns, row) |> Map.new() end)}

      {:error, reason} ->
        {:error, reason}
    end
  end

  @doc """
  Search users by partial name match using parameterized ILIKE.
  """
  def search_users_by_name(name) when is_binary(name) do
    Ecto.Adapters.SQL.query(
      Repo,
      "SELECT id, username, email, role FROM users WHERE username ILIKE $1",
      ["%#{sanitize_like_input(name)}%"]
    )
  end

  @doc """
  Paginated user listing with safe ORDER BY via allowlist.
  """
  def list_users_paginated(sort_by, sort_order, limit, offset)
      when is_integer(limit) and is_integer(offset) do
    safe_sort_column = validate_sort_column(sort_by)
    safe_sort_order = validate_sort_order(sort_order)

    # sort column/order use allowlist validation, not parameterization
    # (identifiers cannot be parameterized in SQL)
    query =
      "SELECT id, username, email, role, inserted_at FROM users " <>
        "ORDER BY #{safe_sort_column} #{safe_sort_order} " <>
        "LIMIT $1 OFFSET $2"

    Ecto.Adapters.SQL.query(Repo, query, [limit, offset])
  end

  # --- Private helpers ---

  # Allowed filter fields mapped to their column names
  @allowed_filters %{
    "role" => "role",
    "email" => "email",
    "username" => "username",
    "active" => "active"
  }

  defp build_where_clauses(filters) do
    filters
    |> Enum.filter(fn {key, value} ->
      Map.has_key?(@allowed_filters, key) and value != "" and value != nil
    end)
    |> Enum.with_index(1)
    |> Enum.reduce({[], []}, fn {{key, value}, index}, {clauses, params} ->
      column = Map.fetch!(@allowed_filters, key)
      # Column name is from our allowlist, not user input - safe to interpolate
      clause = "#{column} = $#{index}"
      {clauses ++ [clause], params ++ [value]}
    end)
  end

  @allowed_sort_columns ~w(id username email role inserted_at)

  defp validate_sort_column(column) when column in @allowed_sort_columns, do: column
  defp validate_sort_column(_), do: "id"

  defp validate_sort_order("desc"), do: "DESC"
  defp validate_sort_order("asc"), do: "ASC"
  defp validate_sort_order(_), do: "ASC"

  defp sanitize_like_input(input) do
    input
    |> String.replace("\\", "\\\\")
    |> String.replace("%", "\\%")
    |> String.replace("_", "\\_")
  end
end

# lib/admin_dashboard_web/controllers/admin/user_controller.ex
defmodule AdminDashboardWeb.Admin.UserController do
  use AdminDashboardWeb, :controller

  alias AdminDashboard.Queries.UserQueries

  def index(conn, params) do
    filters = Map.take(params, ["role", "email", "username", "active"])
    sort_by = Map.get(params, "sort_by", "id")
    sort_order = Map.get(params, "sort_order", "asc")
    page = params |> Map.get("page", "1") |> String.to_integer() |> max(1)
    per_page = params |> Map.get("per_page", "25") |> String.to_integer() |> min(100)
    offset = (page - 1) * per_page

    with {:ok, users} <- UserQueries.filter_users(filters) do
      # Also get paginated results for display
      {:ok, %{rows: rows, columns: columns}} =
        UserQueries.list_users_paginated(sort_by, sort_order, per_page, offset)

      paginated_users = Enum.map(rows, fn row -> Enum.zip(columns, row) |> Map.new() end)

      render(conn, :index,
        users: paginated_users,
        filters: filters,
        page: page,
        per_page: per_page,
        total: length(users)
      )
    end
  end

  def search(conn, %{"q" => query_string}) do
    case UserQueries.search_users_by_name(query_string) do
      {:ok, %{rows: rows, columns: columns}} ->
        users = Enum.map(rows, fn row -> Enum.zip(columns, row) |> Map.new() end)
        json(conn, %{users: users})

      {:error, _reason} ->
        conn |> put_status(500) |> json(%{error: "Search failed"})
    end
  end
end